 57→void test_read_one(char *input, char *expected) {
 58→    int val = read_str(input);
 59→    puts_str(input);
 60→    puts_str(" => ");
 61→    print_val(val);
 62→    puts_str(" [");
 63→    puts_str(expected);
 64→    puts_str("]\n");
 65→}
