 67→void test_reader() {
 68→    /* Integers */
 69→    test_read_one("42", "42");
 70→    test_read_one("-7", "-7");
 71→    test_read_one("0", "0");
 72→
 73→    /* Symbols */
 74→    test_read_one("foo", "foo");
 75→    test_read_one("nil", "nil");
 76→    test_read_one("+", "+");
 77→
 78→    /* Empty list */
 79→    test_read_one("()", "nil");
 80→
 81→    /* Simple list */
 82→    test_read_one("(1 2 3)", "(1 2 3)");
 83→
 84→    /* Dotted pair */
 85→    test_read_one("(1 . 2)", "(1 . 2)");
 86→
 87→    /* Nested list */
 88→    test_read_one("(a (b c))", "(a (b c))");
 89→
 90→    /* Quote */
 91→    test_read_one("'x", "(quote x)");
 92→
 93→    /* Mixed */
 94→    test_read_one("(+ 1 2)", "(+ 1 2)");
 95→    test_read_one("(define x 42)", "(define x 42)");
 96→
 97→    puts_str("reader ok\n");
 98→}
