100→void test_eval_one(char *input, char *expected) {
101→    int expr = read_str(input);
102→    int result = eval(expr, NIL_VAL);
103→    puts_str(input);
104→    puts_str(" => ");
105→    print_val(result);
106→    puts_str(" [");
107→    puts_str(expected);
108→    puts_str("]\n");
