111→void test_eval() {
112→    /* Self-evaluating */
113→    test_eval_one("42", "42");
114→    test_eval_one("-7", "-7");
115→
116→    /* Quote */
117→    test_eval_one("(quote foo)", "foo");
118→    test_eval_one("'(1 2 3)", "(1 2 3)");
119→
120→    /* Arithmetic */
121→    test_eval_one("(+ 1 2)", "3");
122→    test_eval_one("(- 10 3)", "7");
123→    test_eval_one("(* 4 5)", "20");
124→    test_eval_one("(/ 10 3)", "3");
125→
126→    /* Nested arithmetic */
127→    test_eval_one("(+ (* 2 3) (- 10 4))", "12");
128→
129→    /* Comparison */
130→    test_eval_one("(< 1 2)", "t");
131→    test_eval_one("(< 2 1)", "nil");
132→    test_eval_one("(= 5 5)", "t");
133→    test_eval_one("(= 5 6)", "nil");
134→
135→    /* If */
136→    test_eval_one("(if t 1 2)", "1");
137→    test_eval_one("(if nil 1 2)", "2");
138→    test_eval_one("(if (< 1 2) 10 20)", "10");
139→
140→    /* List operations */
141→    test_eval_one("(cons 1 2)", "(1 . 2)");
142→    test_eval_one("(car (cons 1 2))", "1");
143→    test_eval_one("(cdr (cons 1 2))", "2");
144→    test_eval_one("(list 1 2 3)", "(1 2 3)");
145→
146→    /* Predicates */
147→    test_eval_one("(null? nil)", "t");
148→    test_eval_one("(null? 1)", "nil");
149→    test_eval_one("(pair? (cons 1 2))", "t");
150→    test_eval_one("(atom? 42)", "t");
151→    test_eval_one("(not nil)", "t");
152→    test_eval_one("(not t)", "nil");
153→
154→    /* Lambda */
155→    test_eval_one("((lambda (x) (+ x 1)) 41)", "42");
156→    test_eval_one("((lambda (x y) (+ x y)) 3 4)", "7");
157→
158→    /* Begin */
159→    test_eval_one("(begin 1 2 3)", "3");
160→
161→    /* Define and use */
162→    eval(read_str("(define x 42)"), NIL_VAL);
163→    test_eval_one("x", "42");
164→
165→    eval(read_str("(define double (lambda (n) (* n 2)))"), NIL_VAL);
166→    test_eval_one("(double 21)", "42");
167→
168→    /* Higher-order */
169→    eval(read_str("(define apply-twice (lambda (f x) (f (f x))))"), NIL_VAL);
170→    test_eval_one("(apply-twice double 5)", "20");
171→
172→    /* Closure */
173→    eval(read_str("(define make-adder (lambda (n) (lambda (x) (+ n x))))"), NIL_VAL);
174→    eval(read_str("(define add5 (make-adder 5))"), NIL_VAL);
175→    test_eval_one("(add5 10)", "15");
176→
177→    /* Recursion */
178→    eval(read_str("(define fact (lambda (n) (if (= n 0) 1 (* n (fact (- n 1))))))"), NIL_VAL);
179→    test_eval_one("(fact 5)", "120");
180→
181→    puts_str("eval ok\n");
182→}
