184→void test_gc() {
185→    /* Record heap state before GC test */
186→    int before_next = heap_next;
187→
188→    /* Allocate a bunch of garbage (unreachable cells) */
189→    int i = 0;
190→    while (i < 100) {
191→        cons(MAKE_FIXNUM(i), MAKE_FIXNUM(i));
192→        i = i + 1;
193→    }
194→
195→    int after_alloc = heap_next;
196→    puts_str("allocated 100 garbage pairs, heap_next=");
197→    print_int(after_alloc);
198→    putc_uart(10);
199→
200→    /* Force a collection */
201→    gc_collect();
202→
203→    /* Free list should now have cells available */
204→    puts_str("gc collections=");
205→    print_int(gc_collections);
206→    putc_uart(10);
207→
208→    /* Verify reachable data survived: eval a simple expression */
209→    test_eval_one("(+ 1 2)", "3");
210→    test_eval_one("x", "42");
211→    test_eval_one("(double 21)", "42");
212→    test_eval_one("(fact 5)", "120");
213→
214→    /* Allocate more -- should reuse freed cells */
215→    int v1 = cons(MAKE_FIXNUM(99), NIL_VAL);
216→    gc_protect(v1);
217→    puts_str("post-gc cons = ");
218→    print_val(v1);
219→    putc_uart(10);
220→
221→    /* Verify the protected value survives another GC */
222→    gc_collect();
223→    puts_str("after 2nd gc, val = ");
224→    print_val(v1);
225→    putc_uart(10);
226→    gc_unprotect(1);
227→
228→    /* Final check: everything still works */
229→    test_eval_one("(+ 100 200)", "300");
230→
231→    puts_str("gc ok\n");
232→}
