  3→/* eval.h -- Evaluator with core special forms
  4→ *
  5→ * Special forms: quote, if, define, lambda, defmacro, begin
  6→ * Environment: alist of (symbol . value) pairs
  7→ * Closures/macros: extended heap objects
  8→ */
  9→
 10→/* Forward declarations */
 11→int eval(int expr, int env);
 12→int apply_fn(int fn, int args);
 13→
 14→/* Global environment */
 15→int global_env;
 16→
 17→/* Pre-interned special form symbols */
 18→int sym_quote;
 19→int sym_if;
 20→int sym_define;
 21→int sym_lambda;
 22→int sym_defmacro;
 23→int sym_begin;
 24→
 25→/* Primitive IDs */
 26→#define PRIM_ADD     0
 27→#define PRIM_SUB     1
 28→#define PRIM_MUL     2
 29→#define PRIM_DIV     3
 30→#define PRIM_MOD     4
 31→#define PRIM_LT      5
 32→#define PRIM_EQ_NUM  6
 33→#define PRIM_CONS    7
 34→#define PRIM_CAR     8
 35→#define PRIM_CDR     9
 36→#define PRIM_LIST   10
 37→#define PRIM_NULLP  11
 38→#define PRIM_PAIRP  12
 39→#define PRIM_ATOMP  13
 40→#define PRIM_EQP    14
 41→#define PRIM_NOT    15
 42→#define PRIM_PRINT  16
 43→#define PRIM_NUMP   17
 44→
 45→/* --- Extended object accessors --- */
 46→
 47→int ext_type(int v) {
 48→    return heap_car[PTR_IDX(v)];
 49→}
 50→
 51→int ext_data(int v) {
 52→    return heap_cdr[PTR_IDX(v)];
 53→}
 54→
 55→/* --- Extended object constructors --- */
 56→
 57→int make_closure(int params, int body, int env) {
 58→    int inner = cons(body, env);
 59→    int data = cons(params, inner);
 60→    int idx = alloc_cell();
 61→    heap_car[idx] = ETYPE_CLOSURE;
 62→    heap_cdr[idx] = data;
 63→    return MAKE_EXTENDED(idx);
 64→}
 65→
 66→int make_macro(int params, int body, int env) {
 67→    int inner = cons(body, env);
 68→    int data = cons(params, inner);
 69→    int idx = alloc_cell();
 70→    heap_car[idx] = ETYPE_MACRO;
 71→    heap_cdr[idx] = data;
 72→    return MAKE_EXTENDED(idx);
 73→}
 74→
 75→int make_primitive(int id) {
 76→    int idx = alloc_cell();
 77→    heap_car[idx] = ETYPE_PRIMITIVE;
 78→    heap_cdr[idx] = MAKE_FIXNUM(id);
 79→    return MAKE_EXTENDED(idx);
 80→}
 81→
 82→/* Closure/macro field access */
 83→int closure_params(int v) { return car(ext_data(v)); }
 84→int closure_body(int v)   { return car(cdr(ext_data(v))); }
 85→int closure_env(int v)    { return cdr(cdr(ext_data(v))); }
 86→
 87→/* --- Environment --- */
 88→
 89→int env_extend(int sym, int val, int env) {
 90→    return cons(cons(sym, val), env);
 91→}
 92→
 93→int env_lookup(int sym, int env) {
 94→    int e = env;
 95→    while (!IS_NIL(e)) {
 96→        int binding = car(e);
 97→        if (car(binding) == sym) {
 98→            return cdr(binding);
 99→        }
100→        e = cdr(e);
101→    }
102→    e = global_env;
103→    while (!IS_NIL(e)) {
104→        int binding = car(e);
105→        if (car(binding) == sym) {
106→            return cdr(binding);
107→        }
108→        e = cdr(e);
109→    }
110→    puts_str("ERR:unbound ");
111→    print_val(sym);
112→    putc_uart(10);
113→    return NIL_VAL;
114→}
115→
116→int env_bind(int params, int args, int env) {
117→    while (!IS_NIL(params)) {
118→        env = env_extend(car(params), car(args), env);
119→        params = cdr(params);
120→        args = cdr(args);
121→    }
122→    return env;
123→}
124→
125→/* --- Eval --- */
126→
127→int eval_list(int list, int env) {
128→    if (IS_NIL(list)) return NIL_VAL;
129→    int val = eval(car(list), env);
130→    int rest = eval_list(cdr(list), env);
131→    return cons(val, rest);
132→}
133→
134→int apply_primitive(int id, int args) {
135→    int a = NIL_VAL;
136→    int b = NIL_VAL;
137→
138→    if (!IS_NIL(args)) {
139→        a = car(args);
140→        if (!IS_NIL(cdr(args))) {
141→            b = car(cdr(args));
142→        }
143→    }
144→
145→    if (id == PRIM_ADD) return MAKE_FIXNUM(FIXNUM_VAL(a) + FIXNUM_VAL(b));
146→    if (id == PRIM_SUB) return MAKE_FIXNUM(FIXNUM_VAL(a) - FIXNUM_VAL(b));
147→    if (id == PRIM_MUL) return MAKE_FIXNUM(FIXNUM_VAL(a) * FIXNUM_VAL(b));
148→    if (id == PRIM_DIV) return MAKE_FIXNUM(FIXNUM_VAL(a) / FIXNUM_VAL(b));
149→    if (id == PRIM_MOD) return MAKE_FIXNUM(FIXNUM_VAL(a) % FIXNUM_VAL(b));
150→    if (id == PRIM_LT) {
151→        if (FIXNUM_VAL(a) < FIXNUM_VAL(b)) return T_VAL;
152→        return NIL_VAL;
153→    }
154→    if (id == PRIM_EQ_NUM) {
155→        if (FIXNUM_VAL(a) == FIXNUM_VAL(b)) return T_VAL;
156→        return NIL_VAL;
157→    }
158→    if (id == PRIM_CONS) return cons(a, b);
159→    if (id == PRIM_CAR) return car(a);
160→    if (id == PRIM_CDR) return cdr(a);
161→    if (id == PRIM_LIST) return args;
162→    if (id == PRIM_NULLP) {
163→        if (IS_NIL(a)) return T_VAL;
164→        return NIL_VAL;
165→    }
166→    if (id == PRIM_PAIRP) {
167→        if (IS_CONS(a)) return T_VAL;
168→        return NIL_VAL;
169→    }
170→    if (id == PRIM_ATOMP) {
171→        if (!IS_CONS(a)) return T_VAL;
172→        return NIL_VAL;
173→    }
174→    if (id == PRIM_EQP) {
175→        if (a == b) return T_VAL;
176→        return NIL_VAL;
177→    }
178→    if (id == PRIM_NOT) {
179→        if (IS_NIL(a)) return T_VAL;
180→        return NIL_VAL;
181→    }
182→    if (id == PRIM_PRINT) {
183→        print_val(a);
184→        return a;
185→    }
186→    if (id == PRIM_NUMP) {
187→        if (IS_FIXNUM(a)) return T_VAL;
188→        return NIL_VAL;
189→    }
190→
191→    return NIL_VAL;
192→}
193→
194→int eval(int expr, int env) {
195→    /* Self-evaluating */
196→    if (IS_FIXNUM(expr)) return expr;
197→    if (IS_NIL(expr)) return expr;
198→    if (expr == T_VAL) return expr;
199→    if (IS_EXTENDED(expr)) return expr;
200→
201→    /* Symbol lookup */
202→    if (IS_SYMBOL(expr)) {
203→        return env_lookup(expr, env);
204→    }
205→
206→    /* List: special form or function call */
207→    if (!IS_CONS(expr)) return expr;
208→
209→    int head = car(expr);
210→    int args = cdr(expr);
211→
212→    /* quote */
213→    if (head == sym_quote) {
214→        return car(args);
215→    }
216→
217→    /* if */
218→    if (head == sym_if) {
219→        int cond_val = eval(car(args), env);
220→        if (!IS_NIL(cond_val)) {
221→            return eval(car(cdr(args)), env);
222→        }
223→        int else_part = cdr(cdr(args));
224→        if (IS_NIL(else_part)) return NIL_VAL;
225→        return eval(car(else_part), env);
226→    }
227→
228→    /* define */
229→    if (head == sym_define) {
230→        int sym = car(args);
231→        int val = eval(car(cdr(args)), env);
232→        global_env = env_extend(sym, val, global_env);
233→        return val;
234→    }
235→
236→    /* lambda */
237→    if (head == sym_lambda) {
238→        int params = car(args);
239→        int body = car(cdr(args));
240→        return make_closure(params, body, env);
241→    }
242→
243→    /* defmacro: (defmacro name (params) body) */
244→    if (head == sym_defmacro) {
245→        int name = car(args);
246→        int mparams = car(cdr(args));
247→        int mbody = car(cdr(cdr(args)));
248→        int mac = make_macro(mparams, mbody, env);
249→        global_env = env_extend(name, mac, global_env);
250→        return mac;
251→    }
252→
253→    /* begin */
254→    if (head == sym_begin) {
255→        int result = NIL_VAL;
256→        while (!IS_NIL(args)) {
257→            result = eval(car(args), env);
258→            args = cdr(args);
259→        }
260→        return result;
261→    }
262→
263→    /* Function call: eval head */
264→    int fn = eval(head, env);
265→
266→    /* Macro expansion: apply with unevaluated args, then eval result */
267→    if (IS_EXTENDED(fn)) {
268→        if (ext_type(fn) == ETYPE_MACRO) {
269→            int mac_env = env_bind(closure_params(fn), args, closure_env(fn));
270→            int expanded = eval(closure_body(fn), mac_env);
271→            return eval(expanded, env);
272→        }
273→    }
274→
275→    /* Evaluate arguments */
276→    int evaled_args = eval_list(args, env);
277→
278→    return apply_fn(fn, evaled_args);
279→}
280→
281→int apply_fn(int fn, int args) {
282→    if (IS_EXTENDED(fn)) {
283→        int fn_type = ext_type(fn);
284→        if (fn_type == ETYPE_CLOSURE) {
285→            int bound_env = env_bind(closure_params(fn), args, closure_env(fn));
286→            return eval(closure_body(fn), bound_env);
287→        }
288→        if (fn_type == ETYPE_PRIMITIVE) {
289→            int id = FIXNUM_VAL(ext_data(fn));
290→            return apply_primitive(id, args);
291→        }
292→    }
293→    puts_str("ERR:not-fn\n");
294→    return NIL_VAL;
295→}
296→
297→/* --- Initialization --- */
298→
299→void register_prim(char *name, int id) {
300→    int sym = intern(name);
301→    int prim = make_primitive(id);
302→    global_env = env_extend(sym, prim, global_env);
303→}
304→
305→void eval_init() {
306→    global_env = NIL_VAL;
307→
308→    sym_quote = intern("quote");
309→    sym_if = intern("if");
310→    sym_define = intern("define");
311→    sym_lambda = intern("lambda");
312→    sym_defmacro = intern("defmacro");
313→    sym_begin = intern("begin");
314→
315→    register_prim("+", PRIM_ADD);
316→    register_prim("-", PRIM_SUB);
317→    register_prim("*", PRIM_MUL);
318→    register_prim("/", PRIM_DIV);
319→    register_prim("%", PRIM_MOD);
320→    register_prim("<", PRIM_LT);
321→    register_prim("=", PRIM_EQ_NUM);
322→    register_prim("cons", PRIM_CONS);
323→    register_prim("car", PRIM_CAR);
324→    register_prim("cdr", PRIM_CDR);
325→    register_prim("list", PRIM_LIST);
326→    register_prim("null?", PRIM_NULLP);
327→    register_prim("pair?", PRIM_PAIRP);
328→    register_prim("atom?", PRIM_ATOMP);
329→    register_prim("eq?", PRIM_EQP);
330→    register_prim("not", PRIM_NOT);
331→    register_prim("print", PRIM_PRINT);
332→    register_prim("number?", PRIM_NUMP);
333→}
