 1→use tc24r_ast::Program;
 2→use tc24r_codegen_state::CodegenState;
 3→use tc24r_emit_core::emit;
 4→use tc24r_emit_data::{emit_data_section, emit_start};
 5→use tc24r_ops_divmod::emit_divmod_runtime;
 6→
 7→use crate::gen_function::gen_function;
 8→
 9→pub struct Codegen {
10→    pub state: CodegenState,
11→}
12→
13→impl Codegen {
14→    pub fn new() -> Self {
15→        Self {
16→            state: CodegenState::default(),
17→        }
18→    }
19→
20→    pub fn generate(&mut self, program: &Program) -> String {
21→        for g in &program.globals {
22→            self.state.globals.insert(g.name.clone());
23→            self.state.global_types.insert(g.name.clone(), g.ty.clone());
24→        }
25→        self.state.struct_types = program.struct_types.clone();
26→        for func in &program.functions {
27→            self.state
28→                .function_types
29→                .insert(func.name.clone(), func.return_ty.clone());
30→        }
31→        emit(&mut self.state, "        .text");
32→        emit(&mut self.state, "");
33→        emit_start(&mut self.state);
34→        for func in &program.functions {
35→            if func.body.is_none() {
36→                continue; // skip prototypes
37→            }
38→            emit(&mut self.state, "");
39→            gen_function(&mut self.state, func);
40→        }
41→        emit_divmod_runtime(&mut self.state);
42→        emit_data_section(&mut self.state, program);
43→        self.state.out.clone()
44→    }
45→}
