use tc24r_ast::Expr;
use tc24r_codegen_state::CodegenState;
use tc24r_emit_core::{emit_bra, emit_brt, new_label};
use tc24r_emit_macros::emit;

use crate::gen_stmt::gen_stmt;

pub fn gen_expr(expr: &Expr, state: &mut CodegenState) {
    match expr {
        Expr::IntLit(val) => tc24r_expr_literal::gen_int_lit(state, *val),
        Expr::StringLit(s) => tc24r_expr_literal::gen_string_lit(state, s),
        Expr::Ident(name) => tc24r_expr_variable::gen_ident(state, name),
        Expr::Assign { name, value } => {
            tc24r_expr_variable::gen_assign(state, name, value, gen_expr)
        }
        Expr::Call { name, args } => tc24r_expr_call::gen_call(state, name, args, gen_expr),
        Expr::UnaryOp { op, operand } => {
            tc24r_expr_ops::gen_unary_dispatch(state, *op, operand, gen_expr)
        }
        Expr::BinOp { op, lhs, rhs } => {
            tc24r_expr_ops::gen_binop_dispatch(state, *op, lhs, rhs, gen_expr)
        }
        Expr::AddrOf(name) => tc24r_expr_variable::gen_addr_of(state, name),
        Expr::Deref(ptr) => tc24r_expr_pointer::gen_deref(state, ptr, gen_expr),
        Expr::Cast { expr: inner, .. } => gen_expr(inner, state),
        Expr::DerefAssign { ptr, value } => {
            tc24r_expr_pointer::gen_deref_assign(state, ptr, value, gen_expr)
        }
        Expr::PreInc(name) | Expr::PreDec(name) | Expr::PostInc(name) | Expr::PostDec(name) => {
            let delta = match expr {
                Expr::PreInc(_) | Expr::PostInc(_) => 1,
                _ => -1,
            };
            let post = matches!(expr, Expr::PostInc(_) | Expr::PostDec(_));
            tc24r_ops_incdec::gen_inc_dec(state, name, delta, post);
        }
        Expr::StmtExpr(block) => {
            for s in &block.stmts {
                gen_stmt(s, state);
            }
        }
        Expr::MemberAccess { object, member } => {
            tc24r_expr_struct::gen_member_access(state, object, member, gen_expr)
        }
        Expr::MemberAssign {
            object,
            member,
            value,
        } => tc24r_expr_struct::gen_member_assign(state, object, member, value, gen_expr),
        Expr::Ternary {
            cond,
            then_expr,
            else_expr,
        } => gen_ternary(state, cond, then_expr, else_expr),
    }
}

fn gen_ternary(state: &mut CodegenState, cond: &Expr, then_expr: &Expr, else_expr: &Expr) {
    let else_label = new_label(state);
    let done_label = new_label(state);

    gen_expr(cond, state);
    emit!(state, "        ceq     r0,z");
    emit_brt(state, &else_label);
    gen_expr(then_expr, state);
    emit_bra(state, &done_label);
    emit!(state, "{else_label}:");
    gen_expr(else_expr, state);
    emit!(state, "{done_label}:");
}

1→//! Core assembly emission primitives for the COR24 compiler.
2→
3→mod emit;
4→mod immediate;
5→
6→pub use emit::{emit, emit_bra, emit_brf, emit_brt, new_label, resolve_branches};
7→pub use immediate::load_immediate;
8→

  1→//! Basic emit and label helpers.
  2→//!
  3→//! Branch strategy: emit short branches optimistically for all local labels.
  4→//! After each function is generated, `resolve_branches()` checks deferred
  5→//! forward branches against known label positions using cor24-isa range
  6→//! constants, and expands any out-of-range branches to long form.
  7→
  8→use cor24_isa::branch::can_short_branch;
  9→use tc24r_codegen_state::{BranchKind, CodegenState, DeferredBranch};
 10→
 11→/// Append one line of assembly to the output buffer.
 12→/// Auto-detects label lines and records their positions for branch range checking.
 13→pub fn emit(state: &mut CodegenState, line: &str) {
 14→    state.out.push_str(line);
 15→    state.out.push('\n');
 16→    let trimmed = line.trim();
 17→    if trimmed.is_empty() {
 18→        return;
 19→    }
 20→    if trimmed.ends_with(':') {
 21→        let label = &trimmed[..trimmed.len() - 1];
 22→        state
 23→            .label_positions
 24→            .insert(label.to_string(), state.instruction_count);
 25→    } else {
 26→        state.instruction_count += 1;
 27→    }
 28→}
 29→
 30→/// Allocate a fresh unique label and return it.
 31→pub fn new_label(state: &mut CodegenState) -> String {
 32→    let label = format!("L{}", state.label_counter);
 33→    state.label_counter += 1;
 34→    label
 35→}
 36→
 37→/// Emit an unconditional branch to target.
 38→pub fn emit_bra(state: &mut CodegenState, target: &str) {
 39→    if target.starts_with('_') {
 40→        // Global labels — always long form
 41→        emit(state, &format!("        la      r2,{target}"));
 42→        emit(state, "        jmp     (r2)");
 43→        return;
 44→    }
 45→    // Backward branch — check distance now
 46→    if let Some(&label_pos) = state.label_positions.get(target) {
 47→        if can_short_branch(state.instruction_count, label_pos) {
 48→            emit(state, &format!("        bra     {target}"));
 49→        } else {
 50→            emit(state, &format!("        la      r2,{target}"));
 51→            emit(state, "        jmp     (r2)");
 52→        }
 53→        return;
 54→    }
 55→    // Forward branch — emit short optimistically, defer for validation
 56→    let line = format!("        bra     {target}");
 57→    let out_offset = state.out.len();
 58→    emit(state, &line);
 59→    state.deferred_branches.push(DeferredBranch {
 60→        out_offset,
 61→        line,
 62→        instruction_count: state.instruction_count - 1, // emit() already incremented
 63→        target: target.to_string(),
 64→        kind: BranchKind::Bra,
 65→    });
 66→}
 67→
 68→/// Emit a branch-if-true (carry flag set) to target.
 69→pub fn emit_brt(state: &mut CodegenState, target: &str) {
 70→    if target.starts_with('_') {
 71→        emit_long_brt(state, target);
 72→        return;
 73→    }
 74→    if let Some(&label_pos) = state.label_positions.get(target) {
 75→        if can_short_branch(state.instruction_count, label_pos) {
 76→            emit(state, &format!("        brt     {target}"));
 77→        } else {
 78→            emit_long_brt(state, target);
 79→        }
 80→        return;
 81→    }
 82→    let line = format!("        brt     {target}");
 83→    let out_offset = state.out.len();
 84→    emit(state, &line);
 85→    state.deferred_branches.push(DeferredBranch {
 86→        out_offset,
 87→        line,
 88→        instruction_count: state.instruction_count - 1,
 89→        target: target.to_string(),
 90→        kind: BranchKind::Brt,
 91→    });
 92→}
 93→
 94→/// Emit a branch-if-false (carry flag clear) to target.
 95→pub fn emit_brf(state: &mut CodegenState, target: &str) {
 96→    if target.starts_with('_') {
 97→        emit_long_brf(state, target);
 98→        return;
 99→    }
100→    if let Some(&label_pos) = state.label_positions.get(target) {
101→        if can_short_branch(state.instruction_count, label_pos) {
102→            emit(state, &format!("        brf     {target}"));
103→        } else {
104→            emit_long_brf(state, target);
105→        }
106→        return;
107→    }
108→    let line = format!("        brf     {target}");
109→    let out_offset = state.out.len();
110→    emit(state, &line);
111→    state.deferred_branches.push(DeferredBranch {
112→        out_offset,
113→        line,
114→        instruction_count: state.instruction_count - 1,
115→        target: target.to_string(),
116→        kind: BranchKind::Brf,
117→    });
118→}
119→
120→fn emit_long_brt(state: &mut CodegenState, target: &str) {
121→    let skip = new_label(state);
122→    emit(state, &format!("        brf     {skip}"));
123→    emit(state, &format!("        la      r2,{target}"));
124→    emit(state, "        jmp     (r2)");
125→    emit(state, &format!("{skip}:"));
126→}
127→
128→fn emit_long_brf(state: &mut CodegenState, target: &str) {
129→    let skip = new_label(state);
130→    emit(state, &format!("        brt     {skip}"));
131→    emit(state, &format!("        la      r2,{target}"));
132→    emit(state, "        jmp     (r2)");
133→    emit(state, &format!("{skip}:"));
134→}
135→
136→/// Resolve deferred forward branches after a function is fully generated.
137→///
138→/// Checks each deferred short branch against the now-known label positions.
139→/// Out-of-range branches are expanded to long form by replacing the short
140→/// branch line in `state.out`. Processes from end to start so byte offsets
141→/// of earlier entries remain valid.
142→pub fn resolve_branches(state: &mut CodegenState) {
143→    // Process in reverse order so replacements don't shift earlier offsets
144→    let branches: Vec<DeferredBranch> = state.deferred_branches.drain(..).collect();
145→    for branch in branches.iter().rev() {
146→        let Some(&label_pos) = state.label_positions.get(&branch.target) else {
147→            // Label not found — leave as-is (will be a link error or it's in another function)
148→            continue;
149→        };
150→        if can_short_branch(branch.instruction_count, label_pos) {
151→            // Short branch is valid — no change needed
152→            continue;
153→        }
154→        // Need to expand to long form
155→        let short_line_with_newline = format!("{}\n", branch.line);
156→        let long_replacement = match branch.kind {
157→            BranchKind::Bra => {
158→                format!(
159→                    "        la      r2,{}\n        jmp     (r2)\n",
160→                    branch.target
161→                )
162→            }
163→            BranchKind::Brt => {
164→                let skip = new_label(state);
165→                format!(
166→                    "        brf     {skip}\n        la      r2,{}\n        jmp     (r2)\n{skip}:\n",
167→                    branch.target
168→                )
169→            }
170→            BranchKind::Brf => {
171→                let skip = new_label(state);
172→                format!(
173→                    "        brt     {skip}\n        la      r2,{}\n        jmp     (r2)\n{skip}:\n",
174→                    branch.target
175→                )
176→            }
177→        };
178→        let end = branch.out_offset + short_line_with_newline.len();
179→        state.out.replace_range(branch.out_offset..end, &long_replacement);
180→    }
181→}
