 1→//! Variable load helpers.
 2→
 3→use tc24r_codegen_state::CodegenState;
 4→use tc24r_emit_core::load_immediate;
 5→use tc24r_emit_macros::emit;
 6→
 7→/// Load a named variable into r0.
 8→pub fn gen_load_by_name(state: &mut CodegenState, name: &str) {
 9→    if state.globals.contains(name) {
10→        emit!(state, "        la      r1,_{name}");
11→        emit!(state, "        lw      r0,0(r1)");
12→    } else {
13→        let offset = state.locals[name];
14→        emit!(state, "        lw      r0,{offset}(fp)");
15→    }
16→}
17→
18→/// Load the address of a named variable into r0.
19→pub fn gen_addr_of(state: &mut CodegenState, name: &str) {
20→    if state.globals.contains(name) {
21→        emit!(state, "        la      r0,_{name}");
22→    } else {
23→        let offset = state.locals[name];
24→        // r0 = fp + offset
25→        load_immediate(state, offset);
26→        emit!(state, "        add     r0,fp");
27→    }
28→}
