 7→pub fn gen_store_by_name(state: &mut CodegenState, name: &str) {
 8→    if state.globals.contains(name) {
 9→        emit!(state, "        la      r1,_{name}");
10→        emit!(state, "        sw      r0,0(r1)");
11→    } else {
12→        let offset = state.locals[name];
13→        emit!(state, "        sw      r0,{offset}(fp)");
