 1→//! Function prologue and locals allocation.
 2→
 3→use tc24r_codegen_state::CodegenState;
 4→use tc24r_emit_macros::{emit, emit_lines};
 5→
 6→/// Emit the standard function prologue: save fp/r2/r1, set frame pointer,
 7→/// allocate locals.
 8→pub fn emit_prologue(state: &mut CodegenState) {
 9→    emit_lines!(
10→        state,
11→        "        push    fp",
12→        "        push    r2",
13→        "        push    r1",
14→        "        mov     fp,sp",
15→    );
16→    emit_locals_alloc(state);
17→}
18→
19→/// Emit stack adjustment for local variables.
20→///
21→/// Uses `add sp,-N` for small sizes (fits in signed 8-bit immediate),
22→/// `sub sp,N` otherwise.
23→pub fn emit_locals_alloc(state: &mut CodegenState) {
24→    if state.locals_size > 0 {
25→        if state.locals_size <= 127 {
26→            emit!(state, "        add     sp,-{}", state.locals_size);
27→        } else {
28→            emit!(state, "        sub     sp,{}", state.locals_size);
29→        }
30→    }
31→}
