 1→//! Function epilogue generation.
 2→
 3→use tc24r_codegen_state::CodegenState;
 4→use tc24r_emit_macros::{emit_label, emit_lines};
 5→
 6→/// Emit the standard function epilogue: return label, restore sp/r1/r2/fp,
 7→/// jump through return address.
 8→pub fn emit_epilogue(state: &mut CodegenState) {
 9→    let ret_label = state.return_label.clone();
10→    emit_label!(state, ret_label);
11→    emit_lines!(
12→        state,
13→        "        mov     sp,fp",
14→        "        pop     r1",
15→        "        pop     r2",
16→        "        pop     fp",
17→        "        jmp     (r1)",
18→    );
19→}
