            cf_lbl[cf_n] = fl;
            cf_body[cf_n] = fb;
            cf_env[cf_n] = fe;
            cf_n = cf_n + 1;

            puts_str("        la      r0,");
            ce_lr(fl);
            putc_uart(10);
            puts_str("        la      r1,");
            ce_gr(sym);
            putc_uart(10);
            ce("sw      r0,0(r1)");
            return;
        }

