        if (head == cp_lt) {
            int lt = clnew();
            int lx = clnew();
            cexpr(a2, env);
            ce("push    r0");
            cexpr(a1, env);
            ce("pop     r1");
            ce("cls     r0,r1");
            puts_str("        brt     ");
            ce_lr(lt);
            putc_uart(10);
            ce_li(NIL_VAL);
            puts_str("        la      r2,");
            ce_lr(lx);
            putc_uart(10);
            ce("jmp     (r2)");
            ce_ld(lt);
            ce_li(T_VAL);
            ce_ld(lx);
            return;
        }

