        if (head == cp_eq) {
            int lt = clnew();
            int lx = clnew();
            cexpr(a2, env);
            ce("push    r0");
            cexpr(a1, env);
            ce("pop     r1");
            ce("ceq     r0,r1");
            puts_str("        brt     ");
            ce_lr(lt);
            putc_uart(10);
            ce_li(NIL_VAL);
            puts_str("        la      r2,");
            ce_lr(lx);
            putc_uart(10);
            ce("jmp     (r2)");
            ce_ld(lt);
            ce_li(T_VAL);
            ce_ld(lx);
            return;
        }

        /* cons: call runtime _cons */
        if (head == cp_cons_s) {
            cexpr(a2, env);
            ce("push    r0");
            cexpr(a1, env);
            ce("push    r0");
            puts_str("        la      r0,_cons\n");
            ce("jal     r1,(r0)");
            ce("add     sp,6");
            return;
        }

        /* car: call runtime _car */
        if (head == cp_car_s) {
            cexpr(a1, env);
            ce("push    r0");
            puts_str("        la      r0,_car\n");
            ce("jal     r1,(r0)");
            ce("add     sp,3");
            return;
        }

        /* cdr: call runtime _cdr */
        if (head == cp_cdr_s) {
            cexpr(a1, env);
            ce("push    r0");
            puts_str("        la      r0,_cdr\n");
            ce("jal     r1,(r0)");
            ce("add     sp,3");
            return;
        }

        /* null? */
        if (head == cp_nullp) {
            int lt = clnew();
            int lx = clnew();
            cexpr(a1, env);
            ce_li1(NIL_VAL);
            ce("ceq     r0,r1");
            puts_str("        brt     ");
            ce_lr(lt);
            putc_uart(10);
            ce_li(NIL_VAL);
            puts_str("        la      r2,");
            ce_lr(lx);
            putc_uart(10);
            ce("jmp     (r2)");
            ce_ld(lt);
            ce_li(T_VAL);
            ce_ld(lx);
            return;
        }

        /* pair? : check tag == TAG_CONS (1) */
        if (head == cp_pairp) {
            int lt = clnew();
            int lx = clnew();
            cexpr(a1, env);
            ce("lc      r1,3");
            ce("and     r0,r1");
            ce("lc      r1,1");
            ce("ceq     r0,r1");
            puts_str("        brt     ");
            ce_lr(lt);
            putc_uart(10);
            ce_li(NIL_VAL);
            puts_str("        la      r2,");
            ce_lr(lx);
            putc_uart(10);
            ce("jmp     (r2)");
            ce_ld(lt);
            ce_li(T_VAL);
            ce_ld(lx);
            return;
        }

        /* not */
        if (head == cp_not_s) {
            int lt = clnew();
            int lx = clnew();
            cexpr(a1, env);
            ce_li1(NIL_VAL);
            ce("ceq     r0,r1");
            puts_str("        brt     ");
            ce_lr(lt);
            putc_uart(10);
            ce_li(NIL_VAL);
            puts_str("        la      r2,");
            ce_lr(lx);
            putc_uart(10);
            ce("jmp     (r2)");
            ce_ld(lt);
            ce_li(T_VAL);
            ce_ld(lx);
            return;
        }

        /* print: call _print_val, return the printed value */
        if (head == cp_print_s) {
            cexpr(a1, env);
            ce("push    r0");
            ce("push    r0");
            puts_str("        la      r0,_print_val\n");
            ce("jal     r1,(r0)");
            ce("add     sp,3");
            ce("pop     r0");
            return;
        }
    }

    /* --- General function call --- */
    int nargs = clen(args);
    cpush_args(args, env);

    /* Load function address */
    if (IS_SYMBOL(head)) {
        int off = cenv_get(head, env);
        if (off != -9999) {
            puts_str("        lw      r0,");
            print_int(off);
            puts_str("(fp)\n");
        } else {
            cg_add(head);
            puts_str("        la      r1,");
            ce_gr(head);
            putc_uart(10);
            ce("lw      r0,0(r1)");
        }
    } else {
        cexpr(head, env);
    }

    ce("jal     r1,(r0)");
    if (nargs > 0) {
        puts_str("        add     sp,");
        print_int(nargs * 3);
        putc_uart(10);
    }
