/* Emit a compiled function body */
void cemit_fn(int i) {
    ce_ld(cf_lbl[i]);
    ce("push    fp");
    ce("push    r2");
    ce("push    r1");
    ce("mov     fp,sp");
    cexpr(cf_body[i], cf_env[i]);
    ce("mov     sp,fp");
    ce("pop     r1");
    ce("pop     r2");
    ce("pop     fp");
    ce("jmp     (r1)");
}

/* Emit all deferred functions (may grow during emission) */
void cemit_fns() {
    while (cf_done < cf_n) {
        cemit_fn(cf_done);
        cf_done = cf_done + 1;
    }
}

/* Emit data section with global variables */
void cemit_data() {
    if (cg_n == 0) return;
    puts_str("        .data\n");
    int i = 0;
    while (i < cg_n) {
        ce_gr(cg_sym[i]);
        puts_str(":\n        .word   0\n");
        i = i + 1;
    }
}

/* Compile a list of top-level expressions into a program */
void compile_program(int exprs) {
    puts_str("; Generated by tml24c compiler\n");
    puts_str("        .text\n\n");

    puts_str("        .globl  _cmain\n");
    puts_str("_cmain:\n");
    ce("push    fp");
    ce("push    r2");
    ce("push    r1");
    ce("mov     fp,sp");

    while (!IS_NIL(exprs)) {
        cexpr(car(exprs), NIL_VAL);
        exprs = cdr(exprs);
    }

    ce("mov     sp,fp");
    ce("pop     r1");
    ce("pop     r2");
    ce("pop     fp");
    ce("jmp     (r1)");
    putc_uart(10);

    cemit_fns();
    putc_uart(10);

    cemit_data();
}

