            ce_li(NIL_VAL);
        }
        ce_ld(lx);
        return;
    }

    /* begin */
    if (head == sym_begin) {
        while (!IS_NIL(args)) {
            cexpr(car(args), env);
            args = cdr(args);
        }
        return;
    }

    /* define */
    if (head == sym_define) {
        int sym = car(args);
        int vexpr = car(cdr(args));
        cg_add(sym);

        /* Named function: (define name (lambda ...)) */
        if (IS_CONS(vexpr) && car(vexpr) == sym_lambda) {
            int fl = clnew();
            int fp_ = car(cdr(vexpr));
            int fb = car(cdr(cdr(vexpr)));
            int fe = cenv_params(fp_);

            cf_lbl[cf_n] = fl;
            cf_body[cf_n] = fb;
            cf_env[cf_n] = fe;
            cf_n = cf_n + 1;

            puts_str("        la      r0,");
            ce_lr(fl);
            putc_uart(10);
            puts_str("        la      r1,");
            ce_gr(sym);
            putc_uart(10);
            ce("sw      r0,0(r1)");
            return;
        }

        /* General define */
        cexpr(vexpr, env);
        puts_str("        la      r1,");
        ce_gr(sym);
        putc_uart(10);
        ce("sw      r0,0(r1)");
        return;
    }

    /* lambda (anonymous) */
    if (head == sym_lambda) {
        int fl = clnew();
        int fp_ = car(args);
        int fb = car(cdr(args));
        int fe = cenv_params(fp_);

        cf_lbl[cf_n] = fl;
        cf_body[cf_n] = fb;
        cf_env[cf_n] = fe;
        cf_n = cf_n + 1;

        puts_str("        la      r0,");
        ce_lr(fl);
        putc_uart(10);
        return;
    }

    /* --- Inlined primitives --- */
    if (IS_SYMBOL(head)) {
        int a1 = IS_NIL(args) ? NIL_VAL : car(args);
        int a2 = NIL_VAL;
        if (!IS_NIL(args) && !IS_NIL(cdr(args))) {
            a2 = car(cdr(args));
        }

        /* + : tagged fixnum add (tag 0 preserves) */
        if (head == cp_plus) {
            cexpr(a2, env);
            ce("push    r0");
            cexpr(a1, env);
            ce("pop     r1");
            ce("add     r0,r1");
            return;
        }

        /* - : tagged fixnum sub */
        if (head == cp_minus) {
            cexpr(a2, env);
            ce("push    r0");
            cexpr(a1, env);
            ce("pop     r1");
            ce("sub     r0,r1");
            return;
        }

        /* * : untag one operand, multiply */
        if (head == cp_star) {
            cexpr(a2, env);
            ce("push    r0");
            cexpr(a1, env);
            ce("pop     r1");
            ce("lc      r2,2");
            ce("sra     r1,r2");
            ce("mul     r0,r1");
            return;
        }

        /* < : signed compare on tagged values */
        if (head == cp_lt) {
            int lt = clnew();
            int lx = clnew();
            cexpr(a2, env);
            ce("push    r0");
            cexpr(a1, env);
            ce("pop     r1");
            ce("cls     r0,r1");
            puts_str("        brt     ");
            ce_lr(lt);
            putc_uart(10);
            ce_li(NIL_VAL);
            puts_str("        la      r2,");
            ce_lr(lx);
            putc_uart(10);
            ce("jmp     (r2)");
            ce_ld(lt);
            ce_li(T_VAL);
            ce_ld(lx);
            return;
        }

        /* = : equality compare */
        if (head == cp_eq) {
            int lt = clnew();
            int lx = clnew();
            cexpr(a2, env);
            ce("push    r0");
            cexpr(a1, env);
            ce("pop     r1");
            ce("ceq     r0,r1");
            puts_str("        brt     ");
            ce_lr(lt);
            putc_uart(10);
            ce_li(NIL_VAL);
            puts_str("        la      r2,");
            ce_lr(lx);
            putc_uart(10);
            ce("jmp     (r2)");
            ce_ld(lt);
            ce_li(T_VAL);
            ce_ld(lx);
            return;
        }

        /* cons: call runtime _cons */
        if (head == cp_cons_s) {
            cexpr(a2, env);
            ce("push    r0");
            cexpr(a1, env);
            ce("push    r0");
            puts_str("        la      r0,_cons\n");
            ce("jal     r1,(r0)");
            ce("add     sp,6");
            return;
        }

        /* car: call runtime _car */
        if (head == cp_car_s) {
            cexpr(a1, env);
            ce("push    r0");
            puts_str("        la      r0,_car\n");
            ce("jal     r1,(r0)");
            ce("add     sp,3");
            return;
        }

        /* cdr: call runtime _cdr */
        if (head == cp_cdr_s) {
            cexpr(a1, env);
            ce("push    r0");
            puts_str("        la      r0,_cdr\n");
            ce("jal     r1,(r0)");
            ce("add     sp,3");
            return;
        }

        /* null? */
        if (head == cp_nullp) {
            int lt = clnew();
            int lx = clnew();
            cexpr(a1, env);
            ce_li1(NIL_VAL);
            ce("ceq     r0,r1");
            puts_str("        brt     ");
            ce_lr(lt);
            putc_uart(10);
            ce_li(NIL_VAL);
            puts_str("        la      r2,");
            ce_lr(lx);
            putc_uart(10);
            ce("jmp     (r2)");
            ce_ld(lt);
            ce_li(T_VAL);
            ce_ld(lx);
            return;
        }

        /* pair? : check tag == TAG_CONS (1) */
        if (head == cp_pairp) {
            int lt = clnew();
            int lx = clnew();
            cexpr(a1, env);
            ce("lc      r1,3");
            ce("and     r0,r1");
            ce("lc      r1,1");
            ce("ceq     r0,r1");
            puts_str("        brt     ");
            ce_lr(lt);
            putc_uart(10);
            ce_li(NIL_VAL);
            puts_str("        la      r2,");
            ce_lr(lx);
            putc_uart(10);
            ce("jmp     (r2)");
            ce_ld(lt);
            ce_li(T_VAL);
            ce_ld(lx);
            return;
        }

        /* not */
        if (head == cp_not_s) {
            int lt = clnew();
            int lx = clnew();
            cexpr(a1, env);
            ce_li1(NIL_VAL);
            ce("ceq     r0,r1");
            puts_str("        brt     ");
            ce_lr(lt);
            putc_uart(10);
            ce_li(NIL_VAL);
            puts_str("        la      r2,");
            ce_lr(lx);
            putc_uart(10);
            ce("jmp     (r2)");
            ce_ld(lt);
            ce_li(T_VAL);
            ce_ld(lx);
            return;
        }

        /* print: call _print_val, return the printed value */
        if (head == cp_print_s) {
            cexpr(a1, env);
            ce("push    r0");
            ce("push    r0");
            puts_str("        la      r0,_print_val\n");
            ce("jal     r1,(r0)");
            ce("add     sp,3");
            ce("pop     r0");
            return;
        }
    }

    /* --- General function call --- */
    int nargs = clen(args);
    cpush_args(args, env);

    /* Load function address */
    if (IS_SYMBOL(head)) {
        int off = cenv_get(head, env);
        if (off != -9999) {
            puts_str("        lw      r0,");
            print_int(off);
            puts_str("(fp)\n");
        } else {
            cg_add(head);
            puts_str("        la      r1,");
            ce_gr(head);
            putc_uart(10);
            ce("lw      r0,0(r1)");
        }
    } else {
        cexpr(head, env);
    }

    ce("jal     r1,(r0)");
    if (nargs > 0) {
        puts_str("        add     sp,");
        print_int(nargs * 3);
        putc_uart(10);
    }
}

/* Emit a compiled function body */
void cemit_fn(int i) {
    ce_ld(cf_lbl[i]);
    ce("push    fp");
    ce("push    r2");
    ce("push    r1");
    ce("mov     fp,sp");
    cexpr(cf_body[i], cf_env[i]);
    ce("mov     sp,fp");
    ce("pop     r1");
    ce("pop     r2");
    ce("pop     fp");
    ce("jmp     (r1)");
}

/* Emit all deferred functions (may grow during emission) */
void cemit_fns() {
    while (cf_done < cf_n) {
        cemit_fn(cf_done);
        cf_done = cf_done + 1;
    }
}

/* Emit data section with global variables */
void cemit_data() {
    if (cg_n == 0) return;
    puts_str("        .data\n");
    int i = 0;
    while (i < cg_n) {
        ce_gr(cg_sym[i]);
        puts_str(":\n        .word   0\n");
        i = i + 1;
    }
}

/* Compile a list of top-level expressions into a program */
void compile_program(int exprs) {
    puts_str("; Generated by tml24c compiler\n");
    puts_str("        .text\n\n");

    puts_str("        .globl  _cmain\n");
    puts_str("_cmain:\n");
    ce("push    fp");
    ce("push    r2");
    ce("push    r1");
    ce("mov     fp,sp");

    while (!IS_NIL(exprs)) {
        cexpr(car(exprs), NIL_VAL);
        exprs = cdr(exprs);
    }

    ce("mov     sp,fp");
    ce("pop     r1");
    ce("pop     r2");
    ce("pop     fp");
    ce("jmp     (r1)");
    putc_uart(10);

    cemit_fns();
    putc_uart(10);

    cemit_data();
}

